"use client";

import Link from "next/link";
import { MapPin, Plus, Pencil } from "lucide-react";

export default function AddressPage() {

  const addresses = [
    {
      id: 1,
      name: "Mark Cole",
      phone: "+1 234 567 890",
      address:
        "4517 Washington Ave. Manchester, Kentucky 39495",
      type: "Home",
    },
    {
      id: 2,
      name: "Mark Cole",
      phone: "+1 987 654 321",
      address:
        "2118 Thornridge Cir. Syracuse, Connecticut 35624",
      type: "Office",
    },
  ];

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 bg-gray-50 min-h-screen">

      {/* Header */}
      <div className="flex items-center justify-between mb-8">

        <div>
          <h1 className="text-3xl font-bold text-gray-800">
            My Addresses
          </h1>

          <p className="text-gray-500 mt-1">
            Manage your saved delivery addresses
          </p>
        </div>

        {/* Add Address Button */}
        <Link
          href="/profile/address/add"
          className="flex items-center gap-2 bg-[#01A49E] text-white px-5 py-3 rounded-xl transition-all duration-300 hover:bg-[#01857f] hover:shadow-lg"
        >
          <Plus size={18} />
          Add Address
        </Link>

      </div>

      {/* Address Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {addresses.map((item) => (

          <div
            key={item.id}
            className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm transition-all duration-300 hover:shadow-lg hover:border-[#01A49E]/30"
          >

            {/* Top */}
            <div className="flex items-start justify-between mb-5">

              <div className="flex items-center gap-3">

                <div className="w-12 h-12 rounded-full bg-[#01A49E]/10 flex items-center justify-center text-[#01A49E]">
                  <MapPin size={22} />
                </div>

                <div>
                  <h2 className="font-semibold text-lg text-gray-800">
                    {item.type}
                  </h2>

                  <p className="text-sm text-gray-500">
                    Saved Address
                  </p>
                </div>

              </div>

              {/* Edit Button */}
              <Link
                href={`/profile/address/edit/${item.id}`}
                className="p-2 rounded-lg bg-gray-100 text-gray-600 transition-all duration-300 hover:bg-[#01A49E] hover:text-white"
              >
                <Pencil size={18} />
              </Link>

            </div>

            {/* Address Details */}
            <div className="space-y-3">

              <div>
                <p className="text-sm text-gray-500">
                  Full Name
                </p>

                <h3 className="font-semibold text-gray-800 mt-1">
                  {item.name}
                </h3>
              </div>

              <div>
                <p className="text-sm text-gray-500">
                  Phone Number
                </p>

                <h3 className="font-semibold text-gray-800 mt-1">
                  {item.phone}
                </h3>
              </div>

              <div>
                <p className="text-sm text-gray-500">
                  Address
                </p>

                <h3 className="font-semibold text-gray-800 mt-1 leading-7">
                  {item.address}
                </h3>
              </div>

            </div>

          </div>

        ))}

      </div>
    </div>
  );
}